mapper.select:
SELECT a.id, a.subject AS title, a.meeting_nature AS meetingNature, a.visitor_company AS unit, a.industry, a.district, a.applicant, a.phone, a.applicant_dept AS dept, a.start_time AS startTime, a.end_time AS endTime, a.top_leader_title AS leader, a.visitor_count AS headCount, a.customer_count AS customerCount, a.internal_count AS internalCount, a.agenda, a.status, a.create_time AS created, v.actual_visit_count AS actualHeadCount, v.actual_visit_time AS actualVisitTime, v.opportunity_code AS opportunityCode, v.return_signer AS returnSigner, v.return_time AS returnTime, v.status AS visitStatus, COALESCE(p.photo_count, 0) AS photoCount FROM eh_apply a LEFT JOIN eh_visit_record v ON v.apply_id = a.id AND v.del_flag = '0' LEFT JOIN ( SELECT COALESCE(p.apply_id, vr.apply_id) AS apply_id, COUNT(*) AS photo_count FROM eh_visit_photo p LEFT JOIN eh_visit_record vr ON vr.id = p.visit_id AND vr.del_flag = '0' WHERE p.del_flag = '0' GROUP BY COALESCE(p.apply_id, vr.apply_id) ) p ON p.apply_id = a.id WHERE a.del_flag = '0'
AND a.status = #{status}
ORDER BY a.create_time DESC
